import { z } from 'zod';

const envSchema = z.object({
  MONGODB_URI: z.string().url(),
  JWT_SECRET: z.string().min(32),
  TELEGRAM_API_KEY: z.string().min(1),
  ALLOWED_ORIGINS: z.string().transform(str => str.split(',')),
  PORT: z.string().transform(Number),
});

type Env = z.infer<typeof envSchema>;

// Validate the environment variables
export const env: Env = envSchema.parse(process.env);

import { z } from 'zod';
import { ObjectId } from 'mongodb';

export const taskSchema = z.object({
  groupId: z.string().refine(id => ObjectId.isValid(id), {
    message: 'Invalid MongoDB ObjectId',
  }),
  title: z.string().min(1),
  description: z.string(),
  assignees: z.array(z.string().refine(id => ObjectId.isValid(id), {
    message: 'Invalid MongoDB ObjectId',
  })),
  recurrence: z.object({
    type: z.enum(['daily', 'weekly', 'custom']),
    daysOfWeek: z.array(z.number().int().min(0).max(6)).optional(),
    time: z.string().regex(/^\d{2}:\d{2}$/, 'Invalid time format'), // Match HH:mm
  }),
  status: z.enum(['active', 'paused']),
});

import { Task } from '../models/task.model';

export interface TaskDTO {
  id: string;
  groupId: string;
  title: string;
  description: string;
  assignees: string[];
  rotationIndex: number;
  unavailableMembers: string[];
  recurrence: {
    type: string;
    daysOfWeek?: number[];
    time: string;
  };
  status: string;
}

export const toTaskDTO = (task: Task): TaskDTO => ({
  id: task.id.toHexString(),
  groupId: task.groupId.toHexString(),
  title: task.title,
  description: task.description,
  assignees: task.assignees.map(assignee => assignee.toHexString()),
  rotationIndex: task.rotationIndex,
  unavailableMembers: task.unavailableMembers?.map(member => member.toHexString()) || [],
  recurrence: task.recurrence,
  status: task.status,
});

import { Task } from '../models/task.model';
import { AddTaskInput, UpdateTaskInput } from '../validators/task.validator';

class TaskRepository {
  async addTask(input: AddTaskInput) {
    const task = new Task(input);
    await task.save();
    return task;
  }

  async getTaskById(taskId: string) {
    return await Task.findById(taskId);
  }

  async updateTask(taskId: string, input: UpdateTaskInput) {
    const task = await Task.findByIdAndUpdate(taskId, input, { new: true });
    return task;
  }

  async getTasksByGroupId(groupId: string) {
    return await Task.find({ groupId });
  }
}

export const taskRepository = new TaskRepository();

import { taskRepository } from './repositories/task.repository';
import { TaskDTO, toTaskDTO } from './dtos/task.dto';
import { CronJob } from 'cron';
import { sendReminder } from './services/notification.service';

export class SchedulingEngine {
  private static instance: SchedulingEngine;

  private constructor() {}

  static getInstance(): SchedulingEngine {
    if (!this.instance) {
      this.instance = new SchedulingEngine();
    }
    return this.instance;
  }

  public async scheduleTasks(): Promise<void> {
    const tasks = await taskRepository.getTasksByGroupId('someGroupId'); // Example
    tasks.forEach(task => this.scheduleTask(toTaskDTO(task)));
  }

  private scheduleTask(taskDTO: TaskDTO): void {
    const { recurrence: { time }, title, rotationIndex, unavailableMembers, assignees } = taskDTO;
    const cronTime = this.convertTimeToCron(time);

    const job = new CronJob(cronTime, () => {
      let currentAssignee = assignees[rotationIndex];
      if (unavailableMembers.includes(currentAssignee)) {
        currentAssignee = this.findNextAvailableAssignee(taskDTO);
      }
      sendReminder(currentAssignee, title);
    }, null, true, 'Asia/Bangkok');

    job.start();
  }

  private convertTimeToCron(time: string): string {
    const [hour, minute] = time.split(':').map(Number);
    return `${minute} ${hour} * * *`;
  }

  private findNextAvailableAssignee(taskDTO: TaskDTO): string {
    const { assignees, rotationIndex, unavailableMembers } = taskDTO;
    let nextIndex = (rotationIndex + 1) % assignees.length;
    while (unavailableMembers.includes(assignees[nextIndex])) {
      nextIndex = (nextIndex + 1) % assignees.length;
    }
    taskRepository.updateTask(taskDTO.id, { rotationIndex: nextIndex });
    return assignees[nextIndex];
  }
}

import { Telegraf } from 'telegraf';
import { env } from '../config/env';
import winston from 'winston';

const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.Console(),
  ],
});

const bot = new Telegraf(env.TELEGRAM_API_KEY);

export const sendReminder = async (chatId: string, message: string) => {
  try {
    await bot.telegram.sendMessage(chatId, message);
    logger.info('Notification sent', { chatId, timestamp: new Date().toISOString() });
  } catch (error) {
    logger.error('Failed to send notification', { chatId, error, timestamp: new Date().toISOString() });
  }
};
